def most_common_word(s):
    word_count = {}
    for word in s.lower().split():
        if word not in word_count:
            word_count[word] = 0
        word_count[word] += 1
    max_count, max_word = max((value, key) for key, value in word_count.items())
    # edge case: handles the situation when multiple words have the maximum count
    if len({k for k, v in word_count.items() if v == max_count}) > 1:
        max_words = {k for k, v in word_count.items() if v == max_count}
        max_word = min(max_words)
    return max_word
